# MASM-Monolithic-Builder.ps1\n# MONOLITHIC BUILD: All .asm sources → Standard x64 COFF .obj → Single RawrXD.exe\n# Architecture: source = linking - assembling (whitespace = already assembled)\n# Exact artifact map implementation as specified\n\nparam(\n    [string]$Root = \"D:rawrxd\",\n    [string]$OutDir = \"$Root\\build\",\n    [string]$LibDir = \"$Root\\build\\lib\",  \n    [string]$BinDir = \"$Root\\build\\bin\",\n    [string]$MonolithicEXE = \"$BinDir\\RawrXD.exe\",\n    [switch]$KeepPatchedBackup,\n    [int]$BatchSize = 50\n)\n\n$ErrorActionPreference = \"Stop\"\n\n# ============================================================\n# PATCH ENGINE - Fixes the 3 specific bug types\n# ============================================================\n\nfunction Repair-IllegalMemMov($content, $fileName) {\n    $fixed = $content\n    $count = 0\n    \n    # Pattern: mov qword ptr [rbp-8h], qword ptr [rcx] (any mem-to-mem)\n    $pattern = 'mov\\s+(qword|dword|word|byte)?\\s*ptr\\s*(\\[[^\\]]+\\]),\\s*(qword|dword|word|byte)?\\s*ptr\\s*(\\[[^\\]]+\\])'\n    \n    $fixed = [regex]::Replace($content, $pattern, {\n        param($match)\n        $size = $match.Groups[1].Value\n        $dest = $match.Groups[2].Value\n        $src = $match.Groups[4].Value\n        $count++\n        \n        # Generate RAX-routed replacement preserving flags\n        return (\n            \"; [AUTOPATCHED] Illegal mem-to-mem MOV routed through RAX\",\n            \"push rax\",\n            \"mov rax, qword ptr $src\",\n            \"mov qword ptr $dest, rax\",\n            \"pop rax\"\n        ) -join \"`r`n\"\n    }, [System.Text.RegularExpressions.RegexOptions]::Multiline)\n    \n    if($count -gt 0) { Write-Host \"  [PATCH] Fixed $count mem-to-mem MOVs in $fileName\" -Fore Yellow }\n    return $fixed\n}\n\nfunction Repair-TemplateMarkers($content, $fileName) {\n    $fixed = $content\n    $count = 0\n    \n    # Fix single-line markers to START/END pairs\n    # Matches: [GENESIS:SOMETHING] but not [GENESIS:SOMETHING_START] or [GENESIS:SOMETHING_END]\n    $singleMarkers = [regex]::Matches($content, '\\[GENESIS:(\\w+)\\](?!_START|_END)')\n    \n    foreach($match in $singleMarkers | Sort-Object Index -Descending) {\n        $marker = $match.Groups[1].Value\n        $old = $match.Value\n        $newStart = \"[GENESIS:$($marker)_START]\"\n        $newEnd = \"[GENESIS:$($marker)_END]\"\n        \n        # Replace single marker with START/END pair on separate lines\n        $replacement = \"$newStart`r`n[new content here]`r`n$newEnd\"\n        $fixed = $fixed.Substring(0, $match.Index) + $replacement + $fixed.Substring($match.Index + $match.Length)\n        $count++\n    }\n    \n    if($count -gt 0) { Write-Host \"  [PATCH] Converted $count single-line markers to START/END pairs in $fileName\" -Fore Cyan }\n    return $fixed\n}\n\nfunction Repair-MisleadingComments($content, $fileName) {\n    $lines = $content -split \"`r?`n\"\n    $fixedLines = @()\n    $count = 0\n    \n    for($i=0; $i -lt $lines.Count; $i++) {\n        $line = $lines[$i]\n        $fixedLines += $line\n        \n        # Check for \"; marker only\" followed by actual code\n        if($line -match ';.*marker only' -and $i -lt $lines.Count-1) {\n            $nextLine = $lines[$i+1]\n            # If next line has actual assembly instruction (not comment)\n            if($nextLine -match '^\\s+[a-z]+[0-9]?\\s+\\w' -and $nextLine -notmatch '^\\s*;') {\n                $fixedLines[-1] = $line -replace 'marker only', 'marker + implementation'\n                $count++\n            }\n        }\n    }\n    \n    if($count -gt 0) { Write-Host \"  [PATCH] Fixed $count misleading comments in $fileName\" -Fore Green }\n    return ($fixedLines -join \"`r`n\")\n}\n\n# ============================================================\n# MONOLITHIC EXE CONSOLIDATION STRATEGY\n# Consolidates all .obj files into single RawrXD.exe (no subagent splatter)\n# ============================================================\n\nfunction Invoke-MonolithicLink($objFiles, $staticLibs, $outputExe) {\n    Write-Host \"`n[MONOLITHIC-LINK] Consolidating → Single RawrXD.exe\" -Fore Magenta\n    Write-Host \"  Strategy: All subagents as threads (no EXE splatter)\" -Fore Cyan\n    Write-Host \"  Target: $outputExe\" -Fore Gray\n    \n    # Ensure output directory exists\n    $outParent = Split-Path $outputExe -Parent\n    if(!(Test-Path $outParent)) { New-Item -ItemType Directory -Path $outParent -Force | Out-Null }\n    \n    # Find VS linker (link.exe) \n    $linkExe = \"$env:VSINSTALLDIR\\VC\\Tools\\MSVC\\$env:VCToolsVersion\\bin\\Hostx64\\x64\\link.exe\"\n    if(!(Test-Path $linkExe)) {\n        # Fallback search\n        $linkExe = (Get-Command link.exe -ErrorAction SilentlyContinue).Source\n        if(!$linkExe) {\n            # Try common VS installation paths\n            $vsPaths = @(\n                \"C:\\Program Files\\Microsoft Visual Studio\\*\\*\\VC\\Tools\\MSVC\\*\\bin\\Hostx64\\x64\\link.exe\",\n                \"C:\\Program Files (x86)\\Microsoft Visual Studio\\*\\*\\VC\\Tools\\MSVC\\*\\bin\\Hostx64\\x64\\link.exe\"\n            )\n            foreach($pattern in $vsPaths) {\n                $found = Get-ChildItem $pattern -ErrorAction SilentlyContinue | Select-Object -First 1\n                if($found) { $linkExe = $found.FullName; break }\n            }\n        }\n        if(!$linkExe) { throw \"link.exe not found. Install Visual Studio Build Tools.\" }\n    }\n    \n    # Consolidation strategy: Single PE32+ executable (EXACT specification)\n    $linkArgs = @(\n        \"/OUT:`\"$outputExe`\"\",              # Single RawrXD.exe output\n        \"/SUBSYSTEM:WINDOWS\",               # Windows GUI app\n        \"/ENTRY:WinMain\",                   # Standard Windows entry point\n        \"/MACHINE:X64\",                    # x64 architecture\n        \"/LARGEADDRESSAWARE\",               # Support >2GB memory\n        \"/FIXED:NO\",                        # Allow ASLR\n        \"/DYNAMICBASE\",                     # Enable ASLR\n        \"/NXCOMPAT\",                        # NX compatibility\n        \"/NODEFAULTLIB:libcmt\",             # Avoid CRT conflicts\n        \"/MERGE:.rdata=.text\",              # Merge read-only data\n        \"/NOLOGO\"                           # Suppress banner\n    )\n    \n    # Add all .obj files (quoted)\n    foreach($objFile in $objFiles) {\n        $linkArgs += \"`\"$objFile`\"\"\n    }\n    \n    # Add static libraries (quoted)\n    foreach($lib in $staticLibs) {\n        $linkArgs += \"`\"$lib`\"\"\n    }\n    \n    # Add Windows system libraries\n    $linkArgs += @(\n        \"kernel32.lib\", \"user32.lib\", \"gdi32.lib\", \n        \"shell32.lib\", \"ole32.lib\", \"advapi32.lib\"\n    )\n    \n    Write-Host \"  [EXEC] Final consolidation link...\" -Fore White\n    Write-Host \"  [OBJS] $($objFiles.Count) object files\" -Fore Gray\n    Write-Host \"  [LIBS] $($staticLibs.Count) static libraries\" -Fore Gray\n    \n    $proc = Start-Process -FilePath $linkExe -ArgumentList $linkArgs -Wait -PassThru -NoNewWindow\n    \n    if($proc.ExitCode -eq 0) {\n        Write-Host \"  [SUCCESS] RawrXD.exe created → $outputExe\" -Fore Green\n        if(Test-Path $outputExe) {\n            $fileSize = (Get-Item $outputExe).Length\n            Write-Host \"  [SIZE] $(($fileSize/1MB).ToString('F1')) MB\" -Fore Gray\n            Write-Host \"  [PATH] $outputExe\" -Fore Gray\n        }\n    } else {\n        throw \"Monolithic link failed with exit code $($proc.ExitCode)\"\n    }\n    \n    return $outputExe\n}\n\n# ============================================================\n# MAIN MONOLITHIC BUILD PIPELINE\n# ============================================================\n\nWrite-Host @\"\n============================================================\n  MASM MONOLITHIC BUILDER v2.0\n  \n  ARCHITECTURE: source = linking - assembling\n  OUTPUT: Standard x64 COFF .obj → Single RawrXD.exe\n  \n  NO subagent EXEs - all modules as threads in one binary\n============================================================\n\"@ -Fore Magenta\n\nWrite-Host \"Root Dir:         $Root\" -Fore Gray\nWrite-Host \"Output Dir:       $OutDir\" -Fore Gray\nWrite-Host \"Library Dir:      $LibDir\" -Fore Gray\nWrite-Host \"Binary Dir:       $BinDir\" -Fore Gray\nWrite-Host \"Monolithic EXE:   $MonolithicEXE\" -Fore Yellow\nWrite-Host \"Backup Mode:      $KeepPatchedBackup\" -Fore Gray\nWrite-Host \"Batch Size:       $BatchSize sources per batch\" -Fore Gray\nWrite-Host \"Strategy:         All agents as threads → Single process\" -Fore Cyan\nWrite-Host \"================================================\" -Fore Magenta\n\n# Create output directories\nif(!(Test-Path $OutDir)) { New-Item -ItemType Directory -Path $OutDir -Force | Out-Null }\nif(!(Test-Path $LibDir)) { New-Item -ItemType Directory -Path $LibDir -Force | Out-Null }\nif(!(Test-Path $BinDir)) { New-Item -ItemType Directory -Path $BinDir -Force | Out-Null }\n$objDir = Join-Path $OutDir \"obj\"\nif(!(Test-Path $objDir)) { New-Item -ItemType Directory -Path $objDir -Force | Out-Null }\n\n# Discovery phase\n$asmFiles = Get-ChildItem -Path $Root -Filter \"*.asm\" -Recurse | Where-Object {\n    $path = $_.FullName\n    $segments = $path -split '[\\\\\\\\]|/'  \n    # Exclude build directories and archived content\n    foreach($seg in $segments) {\n        if($seg -in @(\"build\", \"dist\", \"temp\", \"obj\", \"bin\", \"lib\") -or $seg -like \".archived*\") {\n            return $false\n        }\n    }\n    return $true\n}\n\nWrite-Host \"Found $($asmFiles.Count) .asm files for processing\" -Fore Green\n\nif($asmFiles.Count -eq 0) {\n    Write-Host \"[ERROR] No .asm files found in $Root\" -Fore Red\n    exit 1\n}\n\n# ============================================================\n# STAGE 1: Generate Standard x64 COFF .obj Files\n# ============================================================\n\nWrite-Host \"`n[STAGE 1] Generating standard x64 COFF .obj files...\" -Fore Yellow\n\n# Find Microsoft Macro Assembler (ml64.exe)\n$ml64Path = (Get-Command ml64.exe -ErrorAction SilentlyContinue).Source\nif(!$ml64Path) {\n    # Search in common VS installation paths\n    $vsPaths = @(\n        \"C:\\Program Files\\Microsoft Visual Studio\\*\\*\\VC\\Tools\\MSVC\\*\\bin\\Hostx64\\x64\\ml64.exe\",\n        \"C:\\Program Files (x86)\\Microsoft Visual Studio\\*\\*\\VC\\Tools\\MSVC\\*\\bin\\Hostx64\\x64\\ml64.exe\",\n        \"C:\\Program Files (x86)\\Microsoft Visual Studio\\*\\VC\\bin\\amd64\\ml64.exe\"\n    )\n    foreach($pattern in $vsPaths) {\n        $found = Get-ChildItem $pattern -ErrorAction SilentlyContinue | Select-Object -First 1\n        if($found) { $ml64Path = $found.FullName; break }\n    }\n}\n\nif(!$ml64Path) {\n    Write-Host \"[ERROR] ml64.exe not found. Install Visual Studio Build Tools with MSVC.\" -Fore Red\n    exit 1\n}\n\nWrite-Host \"  [ASSEMBLER] $ml64Path\" -Fore Green\nWrite-Host \"  [STRATEGY] .asm → patched → ml64.exe → standard x64 COFF .obj\" -Fore Cyan\n\n# Process in batches\n$allObjFiles = [System.Collections.ArrayList]::new()\n$totalFiles = $asmFiles.Count\n$successful = 0\n$failed = 0\n\nfor($start = 0; $start -lt $totalFiles; $start += $BatchSize) {\n    $end = [Math]::Min($start + $BatchSize - 1, $totalFiles - 1)\n    $batch = $asmFiles[$start..$end]\n    $batchNum = [Math]::Floor($start / $BatchSize) + 1\n    $totalBatches = [Math]::Ceiling($totalFiles / $BatchSize)\n    \n    Write-Host \"  [BATCH $batchNum/$totalBatches] Processing $($batch.Count) files...\" -Fore Cyan\n    \n    foreach($asmFile in $batch) {\n        $fileName = [IO.Path]::GetFileNameWithoutExtension($asmFile.Name)\n        $objPath = Join-Path $objDir \"$fileName.obj\"\n        \n        try {\n            # Apply custom compiler patches (preprocessing)\n            $content = Get-Content $asmFile.FullName -Raw -Encoding UTF8\n            \n            # Architecture detection: whitespace = already assembled (skip traditional assembly phase)\n            $hasWhitespace = $content -match '\\s'\n            if($hasWhitespace) {\n                Write-Host \"    [ARCH] $fileName - whitespace detected (pre-assembled)\" -Fore DarkGreen\n            }\n            \n            $patched = Repair-IllegalMemMov $content $asmFile.Name\n            $patched = Repair-TemplateMarkers $patched $asmFile.Name  \n            $patched = Repair-MisleadingComments $patched $asmFile.Name\n            \n            # Create temporary patched file\n            $tempAsm = Join-Path $objDir \"$fileName.temp.asm\"\n            $patched | Out-File $tempAsm -Encoding UTF8\n            \n            # Backup original if patching occurred\n            if($KeepPatchedBackup -and ($patched -ne $content)) {\n                Copy-Item $asmFile.FullName \"$($asmFile.FullName).bak\" -Force\n                Write-Host \"    [BACKUP] Saved → $($asmFile.Name).bak\" -Fore Gray\n            }\n            \n            # Standard MASM assembly: .asm → .obj (COFF x64)\n            & $ml64Path /c /Fo\"$objPath\" \"$tempAsm\" 2>$null\n            \n            if(Test-Path $objPath) {\n                [void]$allObjFiles.Add($objPath)\n                $successful++\n                Write-Host \"    [OK] $fileName.obj\" -Fore Gray\n            } else {\n                $failed++\n                Write-Host \"    [FAIL] $fileName - assembly failed\" -Fore Red\n            }\n            \n            # Cleanup temp file\n            Remove-Item $tempAsm -Force -ErrorAction SilentlyContinue\n            \n        } catch {\n            $failed++\n            Write-Host \"    [FAIL] $fileName - $_\" -Fore Red\n        }\n    }\n}\n\nWrite-Host \"`n============ .OBJ GENERATION SUMMARY =============\" -Fore Magenta\nWrite-Host \"Successful: $successful .obj files\" -Fore Green\nWrite-Host \"Failed:     $failed files\" -Fore Red\nWrite-Host \"Total Size: $($successful + $failed) source files\" -Fore Gray\nWrite-Host \"============================================\" -Fore Magenta\n\nif($allObjFiles.Count -eq 0) {\n    Write-Host \"`n[ERROR] No .obj files generated! Build failed.\" -Fore Red\n    exit 1\n}\n\n# ============================================================\n# STAGE 2: Create Static Libraries (Optional)\n# ============================================================\n\nWrite-Host \"`n[STAGE 2] Creating static libraries...\" -Fore Yellow\n\n# Group obj files by module type (core, gpu, agent, ui, etc.)\n$coreObjs = $allObjFiles | Where-Object { $_ -match 'core|engine|foundation|bridge' }\n$gpuObjs = $allObjFiles | Where-Object { $_ -match 'gpu|cuda|vulkan|compute' }\n$agentObjs = $allObjFiles | Where-Object { $_ -match 'agent|agentic|beacon|patcher' }\n$uiObjs = $allObjFiles | Where-Object { $_ -match 'ui|window|widget|panel|ide' }\n\n$staticLibs = [System.Collections.ArrayList]::new()\n$libTool = (Get-Command lib.exe -ErrorAction SilentlyContinue).Source\n\nif($libTool) {\n    $libs = @{\n        \"rawrxd_core.lib\" = $coreObjs\n        \"rawrxd_gpu.lib\" = $gpuObjs  \n        \"rawrxd_agent.lib\" = $agentObjs\n        \"rawrxd_ui.lib\" = $uiObjs\n    }\n    \n    foreach($libName in $libs.Keys) {\n        $libObjs = $libs[$libName]\n        if($libObjs.Count -gt 0) {\n            $libPath = Join-Path $LibDir $libName\n            & $libTool /NOLOGO /OUT:\"$libPath\" $libObjs 2>$null\n            if(Test-Path $libPath) {\n                [void]$staticLibs.Add($libPath)\n                Write-Host \"  [CREATED] $libName ($($libObjs.Count) objects)\" -Fore Green\n            }\n        }\n    }\n} else {\n    Write-Host \"  [SKIP] lib.exe not found - linking all .obj directly\" -Fore Yellow\n}\n\n# ============================================================\n# STAGE 3: Final Monolithic Link → Single RawrXD.exe\n# ============================================================\n\nWrite-Host \"`n[STAGE 3] Final monolithic link → RawrXD.exe\" -Fore Yellow\nWrite-Host \"  All modules → Single executable (no child processes)\" -Fore Cyan\n\ntry {\n    $finalExe = Invoke-MonolithicLink $allObjFiles $staticLibs $MonolithicEXE\n    \n    Write-Host @\"\n\n============================================================\n  BUILD COMPLETE - MONOLITHIC EXE\n============================================================\n  Output:     $finalExe\n  Modules:    $($allObjFiles.Count) object files\n  Libraries:  $($staticLibs.Count) static libraries\n  Strategy:   All agents as threads in single process\n  \n  EXACT ARTIFACT MAP IMPLEMENTATION:\n  ✓ Standard x64 COFF .obj files\n  ✓ Single RawrXD.exe consolidation\n  ✓ Custom compiler preprocessing\n  ✓ Visual Studio linker integration\n============================================================\n\"@ -Fore Green\n    \n} catch {\n    Write-Host \"`n=== MONOLITHIC LINK FAILED ===\" -Fore Red\n    Write-Host \"Error: $_\" -Fore Red\n    Write-Host \"=============================\" -Fore Red\n    exit 1\n}\n\nWrite-Host \"`nBuild pipeline completed successfully!\" -Fore Magenta\n